{"code": "import json
import re
from collections import defaultdict

# Load California publication numbers
california_path = locals()['var_functions.query_db:14']
with open(california_path, 'r') as f:
    california_patents = json.load(f)

# Extract California publication numbers
california_pub_nums = set()
for patent in california_patents:
    patents_info = patent['Patents_info']
    patterns = [
        r'pub\. number\s+([A-Z]{2}-[A-Z0-9-]+)',
        r'publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
        r'has publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
        r'with publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
        r'has pub\. number\s+([A-Z]{2}-[A-Z0-9-]+)'
    ]
    for pattern in patterns:
        matches = re.findall(pattern, patents_info, re.IGNORECASE)
        if matches:
            california_pub_nums.update(matches)
            break

# Load all patents with citations (the full dataset)
citations_path = locals()['var_functions.query_db:44']
with open(citations_path, 'r') as f:
    patents_with_citations = json.load(f)

# Find patents that cite California patents, excluding UNIV CALIFORNIA itself
citing_patents_by_assignee = defaultdict(list)
university_pattern = re.compile(r'UNIV CALIFORNIA|UNIVERSITY OF CALIFORNIA|UC\s+', re.IGNORECASE)

for patent in patents_with_citations:
    if 'citation' in patent and patent['citation']:
        # Parse the citation JSON
        try:
            citations = json.loads(patent['citation'])
        except:
            citations = []

        # Check if any California publication number appears in the citations
        cited_ca_pubs = []
        for citation in citations:
            if 'publication_number' in citation and citation['publication_number']:
                pub_num = citation['publication_number']
                if pub_num in california_pub_nums:
                    cited_ca_pubs.append(pub_num)

        if cited_ca_pubs:
            # Extract assignee name
            patent_info = patent['Patents_info']
            assignee = None

            patterns = [
                r'^(\w[^,\.]+?)\s+(?:holds|hold the|\s+is assigned|is owned|is belonging|from US,? owned|from US,? held|from US,? assigned)',
                r'(?:assigned to|owned by|belongs to|held by|from US,? owned by|from US,? held by|from US,? assigned to)\s+(\w[^,\.]+?)(?:\s+and has|\s+with pub|\s+,|\s+has|$)',
                r'(?:application \([^\)]+\) from US,\s+(\w[^,]+?)(?:\s+with|,)',
                r'^(\w[\w\s\&\-\.]+?)\s+(?:holds|hold the|\s+is)'
            ]

            for pattern in patterns:
                matches = re.search(pattern, patent_info, re.IGNORECASE)
                if matches:
                    candidate = matches.group(1).strip()
                    # Skip UNIV CALIFORNIA itself
                    if not university_pattern.search(candidate):
                        assignee = candidate
                    break

            if assignee and assignee != patent_info:
                citing_patents_by_assignee[assignee].append({
                    'patent_info': patent_info,
                    'cited_ca_pubs': cited_ca_pubs,
                    'cpc': patent.get('cpc', [])
                })

# Get CPC codes for cited California patents - we need to find primary CPC subclasses
ca_pub_to_cpc = {}
for patent in california_patents:
    # Get California patent's own CPC
    if 'cpc' in patent and patent['cpc']:
        try:
            patent_cpc = json.loads(patent['cpc'])
            # Extract publication number for this California patent
            patents_info = patent['Patents_info']
            patterns = [
                r'pub\. number\s+([A-Z]{2}-[A-Z0-9-]+)',
                r'publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
                r'has publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
                r'with publication number\s+([A-Z]{2}-[A-Z0-9-]+)',
                r'has pub\. number\s+([A-Z]{2}-[A-Z0-9-]+)'
            ]
            pub_num = None
            for pattern in patterns:
                matches = re.findall(pattern, patents_info, re.IGNORECASE)
                if matches:
                    pub_num = matches[0]
                    break

            if pub_num:
                # Find primary CPC subclasses (first inventive = true)
                primary_cpcs = []
                for cpc_entry in patent_cpc:
                    if isinstance(cpc_entry, dict) and cpc_entry.get('inventive', False) and cpc_entry.get('first', False):
                        primary_cpcs.append(cpc_entry.get('code'))

                if primary_cpcs:
                    ca_pub_to_cpc[pub_num] = primary_cpcs
        except:
            pass

print('__RESULT__:')
print(json.dumps({
    'total_citing_assignees': len(citing_patents_by_assignee),
    'total_ca_publications': len(ca_pub_to_cpc),
    'sample_assignees': list(citing_patents_by_assignee.keys())[:10],
    'sample_ca_cpc_mapping': dict(list(ca_pub_to_cpc.items())[:5])
}, indent=2, default=str))"}

